#!/usr/sbin/nft -f
      table inet openshift_filter {
          chain OPENSHIFT {
					type filter hook input priority 1; policy accept;

					# Allow loopback traffic
					iif lo accept

					# Allow established and related traffic
					ct state established,related accept

					# Allow ICMP on ipv4
					ip protocol icmp accept
					# Allow ICMP on ipv6
					ip6 nexthdr ipv6-icmp accept

					# Allow specific TCP and UDP ports
					tcp dport { 22, 80, 111, 443, 2379, 2380, 6080, 6443, 9001, 9099, 9100, 9103, 9104, 9105, 9107, 9108, 9192, 9258, 9637, 9978, 9979, 9980, 10250, 10256, 10257, 10258, 10259, 17697, 22623, 22624, 30000-32767, 32768-60999 } accept
					udp dport { 111, 30000-32767, 32768-60999 } accept

					# Logging and default drop
					log prefix "firewall " drop
				  }
			    }

