table inet ovn-kubernetes {
	set remote-node-ips-v4 {
		type ipv4_addr
		comment "Block egress ICMP needs frag to remote Kubernetes nodes"
	}

	set remote-node-ips-v6 {
		type ipv6_addr
		comment "Block egress ICMPv6 packet too big to remote Kubernetes nodes"
	}

	set udn-open-ports-v4 {
		type ipv4_addr . inet_proto . inet_service
		comment "default network open ports of pods in user defined networks (IPv4)"
	}

	set udn-open-ports-v6 {
		type ipv6_addr . inet_proto . inet_service
		comment "default network open ports of pods in user defined networks (IPv6)"
	}

	set udn-open-ports-icmp-v4 {
		type ipv4_addr
		comment "default network IPs of pods in user defined networks that allow ICMP (IPv4)"
	}

	set udn-open-ports-icmp-v6 {
		type ipv6_addr
		comment "default network IPs of pods in user defined networks that allow ICMP (IPv6)"
	}

	set udn-pod-default-ips-v4 {
		type ipv4_addr
		comment "default network IPs of pods in user defined networks (IPv4)"
	}

	set udn-pod-default-ips-v6 {
		type ipv6_addr
		comment "default network IPs of pods in user defined networks (IPv6)"
	}

	set mgmtport-no-snat-nodeports {
		type inet_proto . inet_service
		comment "NodePorts not subject to management port SNAT"
		elements = { tcp . 31124,
			     tcp . 31639 }
	}

	set mgmtport-no-snat-services-v4 {
		type ipv4_addr . inet_proto . inet_service
		comment "eTP:Local short-circuit not subject to management port SNAT (IPv4)"
	}

	set mgmtport-no-snat-services-v6 {
		type ipv6_addr . inet_proto . inet_service
		comment "eTP:Local short-circuit not subject to management port SNAT (IPv6)"
	}

	set mgmtport-no-snat-subnets-v4 {
		type ipv4_addr
		flags interval
		comment "subnets not subject to management port SNAT (IPv4)"
	}

	set mgmtport-no-snat-subnets-v6 {
		type ipv6_addr
		flags interval
		comment "subnets not subject to management port SNAT (IPv6)"
	}

	map udn-mark-nodeports {
		type inet_proto . inet_service : verdict
		comment "UDN services NodePorts mark"
	}

	map udn-mark-external-ips-v4 {
		type ipv4_addr . inet_proto . inet_service : verdict
		comment "UDN services External IPs mark (IPv4)"
	}

	map udn-mark-external-ips-v6 {
		type ipv6_addr . inet_proto . inet_service : verdict
		comment "UDN services External IPs mark (IPv6)"
	}

	map egress-service-snat-v4 {
		type ipv4_addr : ipv4_addr
	}

	chain no-pmtud {
		comment "Block egress needs frag/packet too big to remote k8s nodes"
		type filter hook output priority filter; policy accept;
		ip daddr @remote-node-ips-v4 icmp type destination-unreachable icmp code frag-needed drop
	}

	chain udn-isolation {
		comment "Host isolation for user defined networks"
		type filter hook output priority filter; policy accept;
		ip daddr . meta l4proto . th dport @udn-open-ports-v4 accept
		ip daddr @udn-open-ports-icmp-v4 meta l4proto icmp accept
		socket cgroupv2 level 2 "system.slice/kubelet.service" ip daddr @udn-pod-default-ips-v4 accept
		ip daddr @udn-pod-default-ips-v4 drop
	}

	chain udn-service-mark {
		comment "UDN services packet mark"
		fib daddr type local meta l4proto . th dport vmap @udn-mark-nodeports
		ip daddr . meta l4proto . th dport vmap @udn-mark-external-ips-v4
		ip6 daddr . meta l4proto . th dport vmap @udn-mark-external-ips-v6
	}

	chain udn-service-prerouting {
		comment "UDN services packet mark - Prerouting"
		type filter hook prerouting priority mangle; policy accept;
		iifname != "ovn-k8s-mp0" jump udn-service-mark
	}

	chain udn-service-output {
		comment "UDN services packet mark - Output"
		type filter hook output priority mangle; policy accept;
		jump udn-service-mark
	}

	chain ovn-kube-pod-subnet-masq {
	}

	chain mgmtport-snat {
		comment "OVN SNAT to Management Port"
		type nat hook postrouting priority srcnat; policy accept;
		oifname != "ovn-k8s-mp0" return
		meta l4proto . th dport @mgmtport-no-snat-nodeports return
		ip saddr 10.128.0.2 return
		ip daddr . meta l4proto . th dport @mgmtport-no-snat-services-v4 return
		ip saddr @mgmtport-no-snat-subnets-v4 return
		snat ip to 10.128.0.2
	}

	chain egress-services {
		type nat hook postrouting priority srcnat; policy accept;
		meta mark 0x000003f0 return comment "DoNotSNAT"
		snat ip to ip saddr map @egress-service-snat-v4
	}
}

